#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
push-setup.py — отправляет агенту «Market Radar» серию сообщений в чат через REST API,
чтобы он сам сохранил все файлы шаблона. Запуск из твоего терминала (одна команда):

    python3 push-setup.py

Ключ можно передать через переменную окружения ASCN_KEY, иначе берётся вшитый ниже.
После прогона проверь раздел Файлы у агента и что первое обращение запускает онбординг.
Рекомендую сменить API-ключ после использования (он передавался в открытом виде).
"""
import base64, json, os, sys, time, uuid
import urllib.request, urllib.error

BASE = "https://api.clawman.ascn.ai/api/v1/workspaces/ws-6iuYwZLBBrQUmk9vicB6gr"
API_KEY = os.environ.get("ASCN_KEY", "<YOUR_ASCN_KEY>")

FILES = json.loads(base64.b64decode("").decode("utf-8"))

def send(sid, content):
    url = BASE + "/session/" + sid + "/messages"
    data = json.dumps({"content": content}).encode("utf-8")
    req = urllib.request.Request(url, data=data, method="POST", headers={
        "Content-Type": "application/json",
        "Authorization": "Bearer " + API_KEY,
    })
    try:
        with urllib.request.urlopen(req, timeout=120) as r:
            return r.status, r.read().decode("utf-8", "replace")
    except urllib.error.HTTPError as e:
        return e.code, e.read().decode("utf-8", "replace")
    except Exception as e:
        return None, repr(e)

def main():
    sid = str(uuid.uuid4())
    print("session_id:", sid)
    intro = ("Ты настраиваешься как шаблон «Market Radar». Сейчас пришлю серию файлов. "
             "Для каждого: создай или перезапиши файл по указанному пути СТРОГО с присланным "
             "содержимым, дословно, без правок. Пока НЕ запускай онбординг — только сохраняй "
             "файлы и коротко подтверждай каждый.")
    st, body = send(sid, intro)
    print("intro ->", st)
    if st is None:
        print("Сеть/эндпоинт недоступны:", body); sys.exit(1)
    time.sleep(2)
    n = len(FILES)
    for i, f in enumerate(FILES, 1):
        msg = (
            "Файл {}/{}: {}\n".format(i, n, f["label"]) +
            "Что это: {}\n".format(f["desc"]) +
            "Куда сохранить (путь в воркспейсе): {}\n".format(f["path"]) +
            "Действие: создай/перезапиши файл по этому пути и вставь содержимое между "
            "маркерами ДОСЛОВНО, один в один, без правок и без самих строк-маркеров.\n" +
            "----- BEGIN {} -----\n".format(f["path"]) +
            f["content"] + "\n" +
            "----- END {} -----".format(f["path"])
        )
        st, body = send(sid, msg)
        print(f["path"], "->", st)
        time.sleep(2)
    final = ("Все файлы отправлены. Перечитай базу знаний и скиллы. С этого момента при первом "
             "обращении пользователя, если setup=PENDING или в watchlist стоит «STATUS: NOT CONFIGURED», "
             "запускай скилл onboarding. Подтверди готовность.")
    st, body = send(sid, final)
    print("final ->", st)
    print("\nГотово. session_id =", sid)

if __name__ == "__main__":
    main()
